// Parse response action request
const request = $input.first().json;

const actions = request.actions || [];
const alert_id = request.alert_id;
const approval_required = request.approval_required || [];

// Separate approved and pending actions
const approved_actions = actions.filter(a => !approval_required.includes(a.type));
const pending_actions = actions.filter(a => approval_required.includes(a.type));

return [{
  json: {
    alert_id,
    approved_actions,
    pending_actions,
    total_actions: actions.length
  }
}];

