// Execute approved actions
const actions = $input.first().json.approved_actions;
const results = [];

for (const action of actions) {
  try {
    // Execute action based on type
    let result;

    switch (action.type) {
      case 'block_ip':
        // Call firewall API
        result = { status: 'success', action: 'block_ip', target: action.target };
        break;
      case 'isolate_host':
        // Call Wazuh active response
        result = { status: 'success', action: 'isolate_host', target: action.target };
        break;
      case 'disable_user':
        // Call AD API
        result = { status: 'success', action: 'disable_user', target: action.target };
        break;
      default:
        result = { status: 'skipped', action: action.type, reason: 'unknown action type' };
    }

    results.push(result);
  } catch (error) {
    results.push({ status: 'failed', action: action.type, error: error.message });
  }
}

return [{ json: { results, alert_id: $input.first().json.alert_id } }];

// Generate response summary
const results = $input.first().json.results;
const alert_id = $input.first().json.alert_id;

const successful = results.filter(r => r.status === 'success').length;
const failed = results.filter(r => r.status === 'failed').length;
const skipped = results.filter(r => r.status === 'skipped').length;

const summary = {
  alert_id,
  total_actions: results.length,
  successful,
  failed,
  skipped,
  results
};

return [{ json: summary }];
